content.text:
Callback funksiyası aşağıdakı şəkildə təyin olunur və istifadə edilir:
```javascript
function esasFunksiya(callback) {
  // Əsas funksiyanın işi
  callback();
}
```
- `callback`: Parametr kimi ötürülən funksiyadır.
- `esasFunksiya`: Callback funksiyasını çağıran funksiyadır.

content.code:
// Sadə callback nümunəsi
function greet(name, callback) {
  const message = 'Salam, ' + name;
  callback(message);
}

function showMessage(text) {
  console.log(text);
}

greet('Ali', showMessage); // Salam, Ali

// Məlumat emalı ilə callback
function processData(data, callback) {
  const result = data * 2;
  callback(result);
}

function displayResult(number) {
  console.log('Nəticə: ' + number);
}

processData(5, displayResult); // Nəticə: 10

// Səhvə yol açan nümunə
function process(number, callback) {
  const result = number + 10;
  callback(result);
}

// Səhv: Callback funksiyası ötürülməyib
process(5); // TypeError: callback is not a function

// Düzgün yol
function showResult(result) {
  console.log('Nəticə: ' + result);
}

process(5, showResult); // Nəticə: 15

// Adi funksiya ilə
const data = 10;
function double(number) {
  return number * 2;
}
console.log(double(data)); // 20

// Callback ilə eyni nəticə
function processWithCallback(number, callback) {
  const result = number * 2;
  callback(result);
}

function showDouble(result) {
  console.log(result);
}

processWithCallback(data, showDouble); // 20

