// Simple callback example
function greet(name, callback) {
  const message = 'Hello, ' + name;
  callback(message);
}

function showMessage(text) {
  console.log(text);
}

greet('Ali', showMessage); // Hello, Ali

// Data processing with callback
function processData(data, callback) {
  const result = data * 2;
  callback(result);
}

function displayResult(number) {
  console.log('Result: ' + number);
}

processData(5, displayResult); // Result: 10

// Error-prone example
function process(number, callback) {
  const result = number + 10;
  callback(result);
}

// Error: No callback provided
process(5); // TypeError: callback is not a function

// Correct approach
function showResult(result) {
  console.log('Result: ' + result);
}

process(5, showResult); // Result: 15

// With a regular function
const data = 10;
function double(number) {
  return number * 2;
}
console.log(double(data)); // 20

// Same result with callback
function processWithCallback(number, callback) {
  const result = number * 2;
  callback(result);
}

function showDouble(result) {
  console.log(result);
}

processWithCallback(data, showDouble); // 20

