// Простой пример callback
function greet(name, callback) {
  const message = 'Привет, ' + name;
  callback(message);
}

function showMessage(text) {
  console.log(text);
}

greet('Али', showMessage); // Привет, Али

// Обработка данных с callback
function processData(data, callback) {
  const result = data * 2;
  callback(result);
}

function displayResult(number) {
  console.log('Результат: ' + number);
}

processData(5, displayResult); // Результат: 10

// Пример с ошибкой
function process(number, callback) {
  const result = number + 10;
  callback(result);
}

// Ошибка: Callback не передан
process(5); // TypeError: callback is not a function

// Правильный подход
function showResult(result) {
  console.log('Результат: ' + result);
}

process(5, showResult); // Результат: 15

// С обычной функцией
const data = 10;
function double(number) {
  return number * 2;
}
console.log(double(data)); // 20

// Тот же результат с callback
function processWithCallback(number, callback) {
  const result = number * 2;
  callback(result);
}

function showDouble(result) {
  console.log(result);
}

processWithCallback(data, showDouble); // 20

